import React, { useEffect, useState } from "react";
import AOS from "aos";
import "aos/dist/aos.css";
import "./HomePage.css";

export default function HomePage() {
  const [showScroll, setShowScroll] = useState(false);
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    AOS.init({ duration: 1000 });
    const handleScroll = () => {
      setShowScroll(window.scrollY > 300);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const toggleDarkMode = () => setDarkMode(!darkMode);

  return (
    <div className={`homepage ${darkMode ? "dark" : ""}`}>
      {/* Navbar */}
      <nav className="navbar">
        <div className="logo">CampusConnect</div>
        <ul className="nav-links">
          <li><a href="#hero">Home</a></li>
          <li><a href="#services">Services</a></li>
          <li><a href="#about">About</a></li>
          <li><a href="#gallery">Gallery</a></li>
          <li><a href="#team">Team</a></li>
          <li><a href="#testimonials">Testimonials</a></li>
          <li><a href="#contact">Contact</a></li>
          <li><a href="/notes">Notes</a></li>
          <li><a href="/internship">Internship</a></li>
          <li><a href="/placement">Placement</a></li>
        </ul>
        <button onClick={toggleDarkMode} className="dark-toggle">
          {darkMode ? "☀️ Light" : "🌙 Dark"}
        </button>
      </nav>

      {/* Hero Section */}
      <section className="hero" id="hero">
        <div data-aos="fade-up">
          <h1>Welcome to CampusConnect</h1>
          <p>Your one-stop platform for campus essentials.</p>
        </div>
      </section>

      {/* Services Section */}
      <section className="services" id="services">
        <h2 data-aos="fade-up">Our Core Services</h2>
        <div className="service-cards">
          <div className="card" data-aos="fade-right">
            <h3>Notes</h3>
            <p>Access and upload class notes easily.</p>
          </div>
          <div className="card" data-aos="fade-up">
            <h3>Internships</h3>
            <p>Find and apply for the best opportunities.</p>
          </div>
          <div className="card" data-aos="fade-left">
            <h3>Placements</h3>
            <p>Prepare and apply for campus placements.</p>
          </div>
        </div>
      </section>

      {/* About Section */}
      <section className="about-section" id="about" data-aos="fade-up">
        <h2>About CampusConnect</h2>
        <p>
          CampusConnect centralizes student needs—from notes to internships—
          into one smart platform built for modern education.
        </p>
      </section>

      {/* Gallery Section */}
      <section className="gallery-section" id="gallery" data-aos="fade-up">
        <h2>Gallery</h2>
        <div className="gallery">
          <img src="/images/notes-page.png" alt="Notes Page" />
          <img src="/images/internships-page.png" alt="Internship Page" />
        </div>
      </section>

      {/* Team Section */}
      <section className="team-section" id="team" data-aos="fade-up">
        <h2>Meet the Team</h2>
        <p>
          A group of developers and students working together to improve campus life with technology.
        </p>
      </section>

      {/* Testimonials Section */}
      <section className="testimonials-section" id="testimonials" data-aos="fade-up">
        <h2>What Students Say</h2>
        <blockquote>"CampusConnect made internship search easy!"</blockquote>
        <blockquote>"Everything I need is now in one place."</blockquote>
      </section>

      {/* Contact Section */}
      <section className="contact-section" id="contact" data-aos="fade-up">
        <h2>Contact Us</h2>
        <form>
          <input type="text" placeholder="Your Name" required />
          <input type="email" placeholder="Your Email" required />
          <textarea placeholder="Your Message" required></textarea>
          <button type="submit">Send</button>
        </form>
      </section>

      {/* Scroll to Top */}
      {showScroll && (
        <button
          className="scroll-to-top"
          onClick={() => window.scrollTo({ top: 0, behavior: "smooth" })}
        >
          ⬆️
        </button>
      )}
    </div>
  );
}
